class Solution {
    public int palindromePartition(String s, int k) {
        int n = s.length();
        int[][] dp = new int[n][n];
        for (int i = n - 1; i >= 0; i--) {
            for (int j = i; j < n; j++) {
                if (i == j) {
                    dp[i][j] = 0;
                } else if (j == i + 1) {
                    dp[i][j] = s.charAt(i) == s.charAt(j) ? 0 : 1;
                } else {
                    dp[i][j] = dp[i + 1][j - 1] + (s.charAt(i) == s.charAt(j) ? 0 : 1);
                }
            }
        }

        int[] partitions = new int[n + 1];
        for (int i = 1; i <= n; i++) {
            partitions[i] = Integer.MAX_VALUE;
            for (int j = 0; j < i; j++) {
                if (k - 1 < j) break;
                partitions[i] = Math.min(partitions[i], partitions[j] + dp[j][i - 1]);
            }
        }
        return partitions[n];
    }
}
